}

{
  "pathway_id": "chondrosarcoma_low_grade_axial_high_grade_clear_cell",
  "title": "Low-Grade Extracompartmental Appendicular Tumors, Grade I Axial Tumors, High-Grade (Grade II/III), Clear Cell, or Extracompartmental Chondrosarcoma",
  "branching_basis": ["Histologic grade", "Location (axial vs appendicular)", "Compartmental status", "Resectability"],
  "nodes": [
    {
      "criteria": "Resectable disease",
      "options": [
        {
          "type": "surgery",
          "label": "Wide excision",
          "preference": "preferred",
          "recommendation": "Must achieve histologically negative surgical margins. May be limb-sparing or amputation [CHON-3, BONE-A].",
          "linked_regimen_ids": []
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "Adjuvant RT may be considered for positive margins or large extracompartmental tumors (category 2B). Radiation is not needed for negative margins [BONE-C 1 of 6]."
      }
    },
    {
      "criteria": "Borderline resectable or unresectable disease",
      "options": [
        {
          "type": "radiation_therapy",
          "label": "Consider RT (category 2B)",
          "preference": "useful_in_certain_circumstances",
          "recommendation": "Consider RT with specialized techniques (e.g., proton beam) for unresectable disease or if positive margins are likely [BONE-C 1 of 6].",
          "linked_regimen_ids": []
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "Not applicable for primary treatment in this setting."
      }
    },
    {
      "criteria": "Metastatic disease (oligometastatic or widespread)",
      "options": [
        {
          "type": "surgery",
          "label": "Surgical excision of all sites if possible",
          "preference": "preferred_for_oligometastatic",
          "recommendation": "For oligometastatic disease, surgical excision of all sites if possible [CHON-4].",
          "linked_regimen_ids": []
        },
        {
          "type": "radiation_therapy",
          "label": "Consider RT for unresectable sites",
          "preference": "useful_in_certain_circumstances",
          "recommendation": "Consider radiation for unresectable sites or as part of palliation [CHON-4].",
          "linked_regimen_ids": []
        },
        {
          "type": "systemic_therapy",
          "label": "Consider systemic therapy (for widespread disease)",
          "preference": "useful_in_certain_circumstances",
          "recommendation": "Dasatinib and pazopanib are category 2A options. Ivosidenib for IDH1-mutant tumors. Consider MGPT, TMB, MMR/MSI testing [BONE-B 1 of 7, CHON-4].",
          "linked_regimen_ids": ["dasatinib_metastatic_chondrosarcoma", "pazopanib_metastatic_chondrosarcoma", "ivosidenib_idh1_mutant"]
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "Not applicable."
      }
    }
  ]
}

